// src/components/WeatherOverlay.jsx
import React, { useMemo } from "react";

/** Safely convert whatever the API gives us into a lowercase condition string */
function normalizeCondition(input) {
  if (typeof input === "string") return input.toLowerCase().trim();

  if (Array.isArray(input) && input.length) {
    const first = input[0];
    if (typeof first === "string") return first.toLowerCase().trim();
    if (first && typeof first === "object") {
      if (typeof first.description === "string") return first.description.toLowerCase().trim();
      if (typeof first.main === "string") return first.main.toLowerCase().trim();
    }
  }

  if (input && typeof input === "object") {
    if (typeof input.description === "string") return input.description.toLowerCase().trim();
    if (typeof input.main === "string") return input.main.toLowerCase().trim();
  }

  if (typeof input === "number") {
    const code = input;
    if ([95, 96, 99].includes(code)) return "thunderstorm";
    if ([71, 73, 75, 77, 85, 86].includes(code)) return "snow";
    if ([51, 53, 55, 56, 57, 61, 63, 65, 66, 67, 80, 81, 82].includes(code)) return "rain";
    if ([45, 48].includes(code)) return "fog";
    if ([0, 1].includes(code)) return "clear";
    return "clouds";
  }

  return "clear";
}

function mapConditionToOverlay(text, isDay) {
  const t = normalizeCondition(text);
  if (t.includes("thunder")) return isDay ? "/overlays/thunderstormdaymobile.gif" : "/overlays/thunderstormnightmobile.gif";
  if (t.includes("rain") || t.includes("drizzle") || t.includes("shower"))
    return isDay ? "/overlays/raindaymobile.gif" : "/overlays/rainnightmobile.gif";
  if (t.includes("snow")) return isDay ? "/overlays/snowdaymobile.gif" : "/overlays/snownightmobile.gif";
  if (t.includes("fog") || t.includes("mist") || t.includes("haze"))
    return isDay ? "/overlays/fogdaymobile.gif" : "/overlays/fognightmobile.gif";
  if (t.includes("cloud")) return isDay ? "/overlays/cloudydaymobile.gif" : "/overlays/cloudynightmobile.gif";
  return isDay ? "/overlays/cleardaymobile.gif" : "/overlays/clearnightmobile.gif";
}

/**
 * Props:
 *   weather: the object returned from /api/weather/current (or hourly-daily),
 *            i.e. { current: {...}, daily: [...], timezone, timezone_offset }
 */
export default function WeatherOverlay({ weather }) {
  // Guard against undefined prop to silence no-undef and avoid runtime errors
  const current = weather?.current ?? {};
  const sunriseMs = current?.sunrise ? current.sunrise * 1000 : null;
  const sunsetMs  = current?.sunset  ? current.sunset  * 1000 : null;

  // Open‑Meteo sometimes provides is_day (0/1). Prefer that; else compute via sunrise/sunset.
  const isDay = useMemo(() => {
    if (typeof current.is_day === "number") return current.is_day === 1;
    const now = Date.now();
    if (sunriseMs && sunsetMs) return now >= sunriseMs && now < sunsetMs;
    // Fallback heuristic if sunrise/sunset missing
    const h = new Date().getUTCHours();
    return h >= 7 && h < 19;
  }, [current.is_day, sunriseMs, sunsetMs]);

  const conditionInput =
    current?.weather ??                 // could be array/object/string
    current?.weather?.[0] ??            // first array item if array
    current?.weather?.[0]?.main ??      // string if present
    "clear";

  const overlaySrc = mapConditionToOverlay(conditionInput, isDay);

  return (
    <div className="absolute inset-0 -z-10 overflow-hidden">
      <img
        src={overlaySrc}
        alt=""
        className="w-full h-full object-cover pointer-events-none select-none"
      />
    </div>
  );
}
